class Book {
  readonly title: string;

  constructor(t: string) {
    this.title = t; // Allowed once
  }
}

let lotr = new Book("LOTR");
console.log(lotr.title); // Works!
// lotr.title = "Hobbit"; ERROR! Read-only!

class Book {
  // This automatically creates a public, readonly property instantly!
  constructor(readonly title: string) {}
}
